$scripts = @(
	{
		& 'C:\Windows\Setup\Scripts\VirtIoGuestTools.ps1';
		Disable-NetAdapterBinding -Name "*" -ComponentID ms_tcpip6 -ErrorAction SilentlyContinue;
		Start-Sleep -Seconds 3;
		Start-Service -Name "QEMU-GA" -ErrorAction SilentlyContinue;
	};
	{
		$drive = (Get-PSDrive -PSProvider FileSystem | Where-Object { Test-Path "$($_.Root)OpenSSH.msi" }).Name;
		if ($drive) {
			Start-Process -FilePath "${drive}:\OpenSSH.msi" -ArgumentList "/qn" -Wait;
			Set-Service -Name sshd -StartupType 'Automatic' -ErrorAction SilentlyContinue;
			Start-Service sshd -ErrorAction SilentlyContinue;
			New-NetFirewallRule -Name "OpenSSH-Server-In-TCP" -DisplayName "OpenSSH SSH Server (Inbound)" -Profile Any -Direction Inbound -Action Allow -Protocol TCP -LocalPort 22 -ErrorAction SilentlyContinue;
		}
	};
	{
		Remove-Item -LiteralPath @(
		  'C:\Windows\Panther\unattend.xml';
		  'C:\Windows\Panther\unattend-original.xml';
		  'C:\Windows\Setup\Scripts\Wifi.xml';
		) -Force -ErrorAction 'SilentlyContinue' -Verbose;
	};
);

& {
  [float] $complete = 0;
  [float] $increment = 100 / $scripts.Count;
  foreach( $script in $scripts ) {
    Write-Progress -Id 0 -Activity 'Running scripts to finalize your Windows installation. Do not close this window.' -PercentComplete $complete;
    '*** Will now execute command «{0}».' -f $(
      $script.ToString().Trim() -replace '\s+', ' ' -replace '^(.{99})(.+)$', '$1…';
    );
    $start = [datetime]::Now;
    & $script;
    '*** Finished executing command after {0:0} ms.' -f [datetime]::Now.Subtract( $start ).TotalMilliseconds;
    "`r`n" * 3;
    $complete += $increment;
  }
} *>&1 | Out-String -Width 1KB -Stream >> "C:\Windows\Setup\Scripts\FirstLogon.log";
